import type { MemoStatus } from '@/lib/types';

/**
 * Ground truth for the eval harness. The corpus is generated by script with
 * known outcomes, so the agent can be scored deterministically — no vibes.
 */
export interface ScenarioGroundTruth {
  docId: string;
  label: string;
  expectedStatus: MemoStatus;
  /** Exact leverage value calc_ratio must have produced for the tested quarter. */
  expectedLeverage: number;
  quarter: string;
  /** The run must show awareness of Amendment No. 2 (cited or read). */
  mustCheckAmendment: boolean;
  /** Material one-off movements the final memo must carry (matched or not). */
  requiredFlaggedIds: string[];
}

